# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from threading import Lock
from collections import defaultdict, Counter
import uuid

app = Flask(__name__)

_data_lock = Lock()
_items = {}
_annotations = defaultdict(list)
_trained_models = []

def majority_vote(labels):
    if not labels:
        return None
    counts = Counter(labels)
    max_count = max(counts.values())
    winners = [label for label, count in counts.items() if count == max_count]
    if len(winners) == 1:
        return winners[0]
    return sorted(winners)[0]

def aggregate_item(item_id):
    labels = [ann["label"] for ann in _annotations[item_id]]
    return majority_vote(labels)

@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(force=True, silent=True) or {}
    image_url = payload.get("image_url")
    if not image_url:
        return jsonify({"error": "image_url is required"}), 400

    item_id = str(uuid.uuid4())
    with _data_lock:
        _items[item_id] = {
            "item_id": item_id,
            "image_url": image_url,
            "metadata": payload.get("metadata", {}),
        }
    return jsonify(_items[item_id]), 201

@app.route("/items", methods=["GET"])
def list_items():
    with _data_lock:
        result = []
        for item_id, item in _items.items():
            result.append({
                "item_id": item_id,
                "image_url": item["image_url"],
                "metadata": item["metadata"],
                "aggregated_label": aggregate_item(item_id)
            })
    return jsonify(result)

@app.route("/items/<item_id>", methods=["GET"])
def get_item(item_id):
    with _data_lock:
        item = _items.get(item_id)
        if not item:
            return jsonify({"error": "item not found"}), 404
        return jsonify({
            "item_id": item_id,
            "image_url": item["image_url"],
            "metadata": item["metadata"],
            "aggregated_label": aggregate_item(item_id),
            "annotations": _annotations[item_id],
        })

@app.route("/items/<item_id>/annotations", methods=["POST"])
def submit_annotation(item_id):
    payload = request.get_json(force=True, silent=True) or {}
    annotator_id = payload.get("annotator_id")
    label = payload.get("label")

    if not annotator_id:
        return jsonify({"error": "annotator_id is required"}), 400
    if label is None:
        return jsonify({"error": "label is required"}), 400

    with _data_lock:
        if item_id not in _items:
            return jsonify({"error": "item not found"}), 404

        existing = None
        for ann in _annotations[item_id]:
            if ann["annotator_id"] == annotator_id:
                existing = ann
                break

        annotation = {
            "annotation_id": str(uuid.uuid4()),
            "annotator_id": annotator_id,
            "label": label,
        }

        if existing:
            existing.update(annotation)
        else:
            _annotations[item_id].append(annotation)

        aggregated = aggregate_item(item_id)

    return jsonify({
        "item_id": item_id,
        "aggregated_label": aggregated,
        "annotation_count": len(_annotations[item_id]),
    }), 201

@app.route("/items/<item_id>/aggregate", methods=["POST"])
def aggregate_endpoint(item_id):
    with _data_lock:
        if item_id not in _items:
            return jsonify({"error": "item not found"}), 404
        aggregated = aggregate_item(item_id)
    return jsonify({
        "item_id": item_id,
        "aggregated_label": aggregated,
    })

@app.route("/train", methods=["POST"])
def train_model():
    payload = request.get_json(force=True, silent=True) or {}
    model_name = payload.get("model_name", "default-model")

    with _data_lock:
        training_data = []
        for item_id, item in _items.items():
            label = aggregate_item(item_id)
            if label is not None:
                training_data.append({
                    "item_id": item_id,
                    "image_url": item["image_url"],
                    "label": label,
                })

    model_record = {
        "model_id": str(uuid.uuid4()),
        "model_name": model_name,
        "num_samples": len(training_data),
        "trained_on": training_data,
    }
    _trained_models.append(model_record)

    return jsonify(model_record), 200

@app.route("/models", methods=["GET"])
def list_models():
    return jsonify(_trained_models)

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)